import {useEffect, useState} from 'react';
import {useNavigate, useSearchParams} from 'react-router-dom';
import axios from 'axios';
import {Loading} from "../../../components/common/Loading";
import {defaultAlert} from "../../../utils/alert";

export function PaymentCallback() {
    const PAYMENT_URL = process.env.REACT_APP_PG_PAYMENT_API_URL;
    const [searchParams] = useSearchParams();
    const navigate = useNavigate();
    const [isLoading, setIsLoading] = useState(true);


    useEffect(() => {
        const checkPayment = async () => {
            // sessionStorage에서 tid 가져오기
            const tid = sessionStorage.getItem('tid');
            const result = searchParams.get('result');


            if (!tid) {
                alert('결제 정보를 찾을 수 없습니다.');
                navigate('/charge');
                return;
            }

            try {
                const payToken = sessionStorage.getItem('payToken'); // 또는 적절한 토큰 가져오기

                if (!payToken) {
                    alert('인증 정보가 없습니다. 다시 로그인해주세요.');
                    navigate('/login');
                    return;
                }

                const url = `${PAYMENT_URL}/api/payment/status/${tid}`;
                for (let i = 0; i < 5; i++) {
                    const response = await axios.get(url, {
                        headers: {
                            'Authorization': `Bearer ${payToken}`
                        }
                    });
                    if (response.data.success) {
                        setIsLoading(false);
                        defaultAlert("결제 완료");

                        // 결제 정보 클리어
                        sessionStorage.removeItem('tid');
                        sessionStorage.removeItem('paymentInProgress');

                        // 저장된 jobPostingCode가 있으면 공고 상세 페이지로 리다이렉트
                        const jobPostingCode = sessionStorage.getItem('jobPostingCode');
                            if (jobPostingCode) {
                                sessionStorage.removeItem('jobPostingCode');
                            navigate(`/job/${jobPostingCode}`, { replace: true });
                        } else {
                            navigate('/charge', { replace: true });
                        }
                        break;
                    }
                }
                // 실패 시에만 여기까지 도달
                sessionStorage.removeItem('tid');
                sessionStorage.removeItem('paymentInProgress');
            } catch (error) {
                console.error('결제 확인 오류:', error);
                alert('결제 결과를 확인할 수 없습니다.');
                navigate('/charge');
            } finally {
                setIsLoading(false);
            }
        };

        checkPayment();
    }, [navigate]);





    return (
        <Loading
            loading={isLoading}
            onClose={() => {
                setIsLoading(false);
                navigate('/charge');
            }}
        />
    );
}
